sql:
SELECT total_earnings
FROM drivers
WHERE driver_id = '1';

SELECT COUNT(*) AS total_ratings
FROM driver_ratings
WHERE driver_id = '0';

SELECT driver_id 
FROM drivers 
ORDER BY driver_id;

SELECT document_type, COUNT(*) AS document_count
FROM rider_documents
GROUP BY document_type;

external_knowledge:
; Completed trips refer to trips that have reached their destination and have been marked as 'completed' in the system; 
; Vehicle types can include sedans, SUVs, and other categories of vehicles used for trips;
; Average costs are calculated based on the total cost of all trips for a given vehicle type, divided by the number of trips.

